def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0 or item > capacity:
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.1:
            score += np.exp(-10 * ratio) * (1 - ratio) * 5
        elif 0.1 <= ratio < 0.3:
            score += np.log1p(ratio * 10) * 3 - ratio**1.5
        elif 0.3 <= ratio < 0.6:
            score += np.sin(10*ratio) * np.cos(5*ratio) + 1
        else:
            score += np.tanh(15*(ratio - 0.5)) + np.sqrt(ratio)
        penalty_sum = 0
        for p in range(1, 10):
            mod_val = (item * p + p**2) % capacity
            frac = mod_val / (capacity * p + 1)
            if frac < 0.1:
                penalty_sum += frac * 4 / p
            elif frac < 0.3:
                penalty_sum += frac * 2 / np.sqrt(p)
            elif frac < 0.6:
                penalty_sum += frac / (p + ratio + 0.5)
            else:
                penalty_sum += (frac ** 1.1) / (p**2 + 1)
        complexity = 0
        for a in range(1,5):
            for b in range(1,6):
                val = (ratio * a + b**2) % 1
                if val < 0.2:
                    complexity += np.sin(val * np.pi * 2) / (a*b)
                elif val < 0.5:
                    complexity += np.cos(val * np.pi) / (a + b)
                elif val < 0.8:
                    complexity += (val ** 3) / (a*b + 1)
                else:
                    complexity += np.tanh(val * 5) / (a + 2*b)
        extra = 0
        for k in range(1,8):
            if ratio * k < 1:
                exp_val = np.exp(-k * ratio) * k
                extra += exp_val if exp_val < 2 else 2
            else:
                extra += np.log1p(k**3 * ratio) / (k+1)
        if capacity % 4 == 0 and capacity % 6 != 0:
            total_score = score + penalty_sum * 0.75 + complexity * 0.6 + extra * 0.9
        elif capacity % 6 == 0:
            total_score = score + penalty_sum * 1.1 + complexity * 0.9 + extra * 0.7
        else:
            total_score = score + penalty_sum + complexity + extra
        if total_score < 0:
            total_score = 0
        priorities[i] = total_score
    return priorities
